# shapes.spy - Shape classes implementing interfaces from types module
from types import Color, Point, Drawable, Measurable, Positionable

@abstract
class Shape(Drawable):
    color: Color

    def __init__(self, color: Color):
        self.color = color

    @virtual
    def get_description(self) -> str:
        return "A shape"

    @abstract
    def get_name(self) -> str:
        ...

class Rectangle(Shape, Measurable, Positionable):
    width: float
    height: float
    _position: Point

    def __init__(self, width: float, height: float, color: Color):
        super().__init__(color)
        self.width = width
        self.height = height
        self._position = Point(0.0, 0.0)

    @override
    def draw(self) -> None:
        print("Drawing rectangle")

    @override
    def get_name(self) -> str:
        return "Rectangle"

    @override
    def get_description(self) -> str:
        return "A rectangle with width " + str(self.width) + " and height " + str(self.height)

    @override
    def get_area(self) -> float:
        return self.width * self.height

    @override
    def get_measure(self) -> str:
        return "Area: " + str(self.get_area())

    @override
    def get_position(self) -> Point:
        return self._position

    @override
    def set_position(self, value: Point) -> None:
        self._position = value

    @override
    def get_x(self) -> float:
        return self._position.x

    @override
    def get_y(self) -> float:
        return self._position.y

class Circle(Shape, Measurable, Positionable):
    radius: float
    _position: Point

    def __init__(self, radius: float, color: Color):
        super().__init__(color)
        self.radius = radius
        self._position = Point(0.0, 0.0)

    @override
    def draw(self) -> None:
        print("Drawing circle")

    @override
    def get_name(self) -> str:
        return "Circle"

    @override
    def get_description(self) -> str:
        return "A circle with radius " + str(self.radius)

    @override
    def get_area(self) -> float:
        # Pi * r^2, approximating pi as 3.14159
        return 3.14159 * self.radius * self.radius

    @override
    def get_measure(self) -> str:
        return "Circle area: " + str(self.get_area())

    @override
    def get_position(self) -> Point:
        return self._position

    @override
    def set_position(self, value: Point) -> None:
        self._position = value

    @override
    def get_x(self) -> float:
        return self._position.x

    @override
    def get_y(self) -> float:
        return self._position.y

class Square(Rectangle):
    def __init__(self, side: float, color: Color):
        # Square has equal width and height
        super().__init__(side, side, color)

    @override
    def get_name(self) -> str:
        return "Square"

    @override
    def get_description(self) -> str:
        return "A square with side " + str(self.width)

