# utils.spy - Utility functions and helper classes
from types import Point, Color, Measurable
from shapes import Shape, Rectangle, Circle

class ShapeCalculator:
    @static
    def total_area(measurables: list[Measurable]) -> float:
        total: float = 0.0
        for m in measurables:
            total = total + m.get_area()
        return total

    @static
    def count_by_color(shapes: list[Shape], color: Color) -> int:
        count: int = 0
        for shape in shapes:
            if shape.color == color:
                count = count + 1
        return count

def create_rectangle_at(x: float, y: float, width: float, height: float) -> Rectangle:
    rect: Rectangle = Rectangle(width, height, Color.BLUE)
    rect.set_position(Point(x, y))
    return rect

def get_color_name(color: Color) -> str:
    match color:
        case Color.RED:
            return "Red"
        case Color.GREEN:
            return "Green"
        case Color.BLUE:
            return "Blue"
        case _:
            return "Other"

class ShapeRenderer:
    shapes: list[Shape]

    def __init__(self):
        self.shapes = []

    def add(self, shape: Shape) -> None:
        self.shapes.append(shape)

    def render_all(self) -> None:
        for shape in self.shapes:
            shape.draw()
            print(shape.get_name())
